import React from 'react'

function Recommendcarousel() {
  const cardsData = [
    { title: "Deva", img: "allpandya.jpeg" },
    { title: "Shiva", img: "https://via.placeholder.com/150" },
    { title: "Vishnu", img: "https://via.placeholder.com/150" },
    { title: "Brahma", img: "https://via.placeholder.com/150" },
    { title: "Lakshmi", img: "https://via.placeholder.com/150" },
    { title: "Parvati", img: "https://via.placeholder.com/150" },
    { title: "Kali", img: "https://via.placeholder.com/150" },
    { title: "Ganesha", img: "https://via.placeholder.com/150" }
  ];

  const CardCarousel = () => {
    const chunkSize = 4;
    const slides = [];

    for (let i = 0; i < cardsData.length; i += chunkSize) {
      slides.push(cardsData.slice(i, i + chunkSize));
    }

    return (
      <div id="cardCarousel" className="carousel slide" data-bs-ride="carousel">
        <div className="carousel-inner">
          {slides.map((group, index) => (
            <div className={`carousel-item ${index === 0 ? "active" : ""}`} key={index}>
              <div className="d-flex justify-content-around">
                {group.map((card, idx) => (
                  <div className="card" style={{ width: "18rem" }} key={idx}>
                    <img src={card.img} className="card-img-top" alt={card.title} />
                    <div className="card-body">
                      <h5 className="card-title">{card.title}</h5>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Carousel Controls */}
        <button className="carousel-control-prev" type="button" data-bs-target="#cardCarousel" data-bs-slide="prev">
          <span className="carousel-control-prev-icon" aria-hidden="true"></span>
          <span className="visually-hidden">Previous</span>
        </button>
        <button className="carousel-control-next" type="button" data-bs-target="#cardCarousel" data-bs-slide="next">
          <span className="carousel-control-next-icon" aria-hidden="true"></span>
          <span className="visually-hidden">Next</span>
        </button>
      </div>
    );
  };

}

export default Recommendcarousel;
